previewCss:
.darma-loader-darma-research-prism-marquee-loader { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #ec4899); --accent-2: var(--loader-secondary-color, #22d3ee); width: calc(var(--loader-size, 72px) * 2.7); min-width: 170px; display: grid; gap: 10px; font: 800 13px/1 ui-monospace, SFMono-Regular, Menlo, monospace; letter-spacing: .35em; color: transparent; }
.darma-loader-darma-research-prism-marquee-loader__label { background: linear-gradient(90deg, var(--accent), var(--accent-2), var(--accent)); background-size: 240% 100%; -webkit-background-clip: text; background-clip: text; animation: darma-loader-darma-research-prism-marquee-loader-prism-text calc(var(--speed) * 2.4) linear infinite; }
.darma-loader-darma-research-prism-marquee-loader__track { height: 14px; border-radius: 999px; overflow: hidden; background: #111827; box-shadow: inset 0 0 0 1px #ffffff1f; position: relative; }
.darma-loader-darma-research-prism-marquee-loader__fill { position: absolute; inset: 2px auto 2px 2px; width: 42%; border-radius: inherit; background: repeating-linear-gradient(115deg, var(--accent) 0 12px, var(--accent-2) 12px 24px, #fff 24px 28px); box-shadow: 0 0 18px var(--accent); animation: darma-loader-darma-research-prism-marquee-loader-prism-fill calc(var(--speed) * 1.5) cubic-bezier(.7,0,.25,1) infinite; }
@keyframes darma-loader-darma-research-prism-marquee-loader-prism-fill { 0% { translate: -105% 0; width: 38%; } 45% { width: 70%; } 100% { translate: 250% 0; width: 38%; } }
@keyframes darma-loader-darma-research-prism-marquee-loader-prism-text { to { background-position: 240% 0; } }

